// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA.
//
// Reference: emb = cat(freqs, freqs); cos = emb.cos()*scale -> bf16;
//            sin = emb.sin()*scale -> bf16.  freqs is [B,S,64] fp32, outputs
//            are [B,S,128] bf16.  head_dim=128 (const) so half=64.
//
// Design (4 freqs/thread, advancing the 2-freq float2 frontier):
//   * Each unique frequency's (cos,sin) is written to TWO output columns
//     (col and col+64) — we compute the SFU work ONCE and duplicate the store.
//   * 4 frequencies per thread: one 16-byte float4 load (128-bit), and PACKED
//     64-bit stores (uint64_t = 4 bf16 at once) to each half — wider memory
//     transactions, half the load/store instructions of the 2-freq approach.
//     4 adjacent freqs are always in the same 64-wide row (64 is a multiple of
//     4), and low/high-half targets are 8-byte aligned (col is a multiple of 4),
//     so the uint64_t packed stores are always legal.
//   * Double-precision range reduction to [-pi,pi] before __sincosf — required
//     for correctness under --use_fast_math where __sincosf uses the hardware
//     MUFU path with limited range-reduction precision.
//   * Per-shape block sizing: 512 threads for tiny shapes (fewer blocks =
//     less scheduling overhead), 256 for larger shapes (enough blocks to fill
//     SMs).  Natural grid = cdiv(n_quads, block) — no over-spreading.

#include <torch/extension.h>
#include <cuda_bf16.h>
#include <tuple>

#define HALF 64
#define FULL 128

__device__ inline uint32_t bf162_as_u32(__nv_bfloat162 x) {
    union { __nv_bfloat162 bf; uint32_t u32; } u;
    u.bf = x;
    return u.u32;
}

__global__ void fused_rope_kernel(const float* __restrict__ freqs,
                                   __nv_bfloat16* __restrict__ cos_out,
                                   __nv_bfloat16* __restrict__ sin_out,
                                   long n_quads, float scale) {
    long t = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (t >= n_quads) return;

    // 4 frequencies per thread: one 16-byte (128-bit) coalesced load.
    float4 f = reinterpret_cast<const float4*>(freqs)[t];

    // Double-precision range reduction to [-pi,pi] — robust under --use_fast_math
    // where __sincosf becomes the hardware MUFU path with limited reduction.
    const double TWO_PI = 6.283185307179586476925286766559;
    double x0 = (double)f.x, x1 = (double)f.y, x2 = (double)f.z, x3 = (double)f.w;
    float r0 = (float)(x0 - TWO_PI * rint(x0 / TWO_PI));
    float r1 = (float)(x1 - TWO_PI * rint(x1 / TWO_PI));
    float r2 = (float)(x2 - TWO_PI * rint(x2 / TWO_PI));
    float r3 = (float)(x3 - TWO_PI * rint(x3 / TWO_PI));

    float s0, c0, s1, c1, s2, c2, s3, c3;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);
    __sincosf(r2, &s2, &c2);
    __sincosf(r3, &s3, &c3);

    // Scale and pack into bfloat162 pairs (round-to-nearest-even, matches torch .to(bf16)).
    __nv_bfloat162 c01 = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 c23 = __floats2bfloat162_rn(c2 * scale, c3 * scale);
    __nv_bfloat162 s01 = __floats2bfloat162_rn(s0 * scale, s1 * scale);
    __nv_bfloat162 s23 = __floats2bfloat162_rn(s2 * scale, s3 * scale);

    // Pack 4 bf16 values into uint64_t for a single 64-bit store per half.
    uint64_t c_packed = ((uint64_t)bf162_as_u32(c23) << 32) | bf162_as_u32(c01);
    uint64_t s_packed = ((uint64_t)bf162_as_u32(s23) << 32) | bf162_as_u32(s01);

    // Map quad index to output positions.  four_t = frequency index; each row
    // has 64 freqs (128 bf16 outputs).  lo_idx indexes into uint64_t* view
    // (4 bf16 per element).  hi_idx = lo_idx + 64/4 = lo_idx + 16.
    long four_t = t << 2;         // t * 4
    long row    = four_t >> 6;    // / 64
    long col    = four_t & 63;    // % 64
    long lo_idx = (row << 5) + (col >> 2);  // row*32 + col/4
    long hi_idx = lo_idx + 16;    // + 64/4

    uint64_t* cos_u64 = reinterpret_cast<uint64_t*>(cos_out);
    uint64_t* sin_u64 = reinterpret_cast<uint64_t*>(sin_out);
    cos_u64[lo_idx] = c_packed;
    cos_u64[hi_idx] = c_packed;
    sin_u64[lo_idx] = s_packed;
    sin_u64[hi_idx] = s_packed;
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();
    const int64_t B    = freqs.size(0);
    const int64_t S    = freqs.size(1);
    const int64_t half = freqs.size(2);   // 64
    const int64_t full = half * 2;        // 128
    const int64_t n_freqs = B * S * half;
    const int64_t n_quads = n_freqs / 4;  // n_freqs is always a multiple of 64 → multiple of 4

    auto opts = torch::TensorOptions().dtype(torch::kBFloat16).device(freqs.device());
    auto cos_out = torch::empty({B, S, full}, opts);
    auto sin_out = torch::empty({B, S, full}, opts);

    if (n_quads > 0) {
        // Per-shape block sizing: larger blocks for tiny shapes reduce
        // scheduling overhead; smaller blocks for large shapes fill 148 SMs.
        int block = (n_quads <= 32768) ? 512 : 256;
        int grid = (int)((n_quads + block - 1) / block);
        cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();
        fused_rope_kernel<<<grid, block, 0, stream>>>(
            freqs.data_ptr<float>(),
            reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
            reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
            n_quads, (float)attention_scaling);
    }
    return std::make_tuple(cos_out, sin_out);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "fused cos/sin RoPE embedding generation (CUDA)");
}

